mapper.select:
with candidates as (
  select integration_event_id from integration_event_outbox
  where status='PENDING'
     or (status='RETRY_WAITING' and (next_attempt_at is null or next_attempt_at <= #{now}))
     or (status='DELIVERING' and (claim_until is null or claim_until <= #{now}))
  order by created_at asc for update skip locked limit #{limit}
)
update integration_event_outbox e set status='DELIVERING',claimed_by=#{workerId},claim_until=#{claimUntil},updated_at=#{now}
from candidates c where e.integration_event_id=c.integration_event_id returning e.*
